function scrollElementOSToTop() {
  if (typeof window === "undefined") return;
  try {
    window.scrollTo({ top: 0, left: 0, behavior: "auto" });
  } catch (_error) {
    window.scrollTo(0, 0);
  }
  try {
    document.documentElement.scrollTop = 0;
    document.body.scrollTop = 0;
    document.querySelectorAll(".eos-scroll-root, .eos-page-stage, main").forEach((node) => {
      if (node && typeof node.scrollTo === "function") node.scrollTo({ top: 0, left: 0, behavior: "auto" });
      else if (node) node.scrollTop = 0;
    });
  } catch (_error) {
    // Best-effort only. Never block navigation if the browser refuses scroll access.
  }
}

function safeParseJSON(value, fallback) {
  try {
    if (value === null || value === undefined || value === "") return fallback;
    return JSON.parse(value);
  } catch (_error) {
    return fallback;
  }
}

function safeArray(value, fallback = []) {
  return Array.isArray(value) ? value : fallback;
}

function safeNumber(value, fallback = 0) {
  const next = Number(value);
  return Number.isFinite(next) ? next : fallback;
}

function showToast(message) {
  if (typeof window === "undefined") return;
  try {
    window.dispatchEvent(new CustomEvent("elementos:toast", { detail: { message } }));
  } catch (_error) {
    console.log("ElementOS:", message);
  }
}

class ElementOSPageErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { error: null };
  }
  static getDerivedStateFromError(error) {
    return { error };
  }
  componentDidCatch(error, info) {
    console.error("ElementOS page crash:", error, info);
  }
  componentDidUpdate(prevProps) {
    if (prevProps.page !== this.props.page && this.state.error) {
      this.setState({ error: null });
    }
  }
  render() {
    if (!this.state.error) return this.props.children;
    return (
      <div className="rounded-[2rem] border border-red-300/25 bg-red-300/[0.08] p-6 text-red-50">
        <div className="text-xs font-black uppercase tracking-[.22em] text-red-200">Page safety guard</div>
        <h2 className="mt-2 text-3xl font-black">{pageLabel(this.props.page)} hit a render error.</h2>
        <p className="mt-3 text-sm leading-6 text-red-100/90">This view could not load cleanly. The rest of ElementOS is still available, so return to the dashboard or retry the page.</p>
        <div className="mt-4 flex flex-wrap gap-2">
          <button type="button" onClick={() => this.setState({ error: null })} className="rounded-full bg-red-100 px-4 py-2 text-sm font-black text-red-950">Retry Page</button>
          <button type="button" onClick={() => this.props.setPage?.("dashboard")} className="rounded-full border border-red-100/30 px-4 py-2 text-sm font-black text-red-50">Back to Mission Intelligence</button>
        </div>
      </div>
    );
  }
}



