                      height: `${size}px`,
                      left: `calc(50% + ${Math.cos(dot.angle) * dot.ring}px - ${size / 2}px)`,
                      top: `calc(50% + ${Math.sin(dot.angle) * dot.ring}px - ${size / 2}px)`,
                      transform: i % 11 === 0 ? "scale(1.16)" : "scale(1)",
