function v211ReportIntentForPage(page, selected = "Al", compare = []) {
  const source = V211_REPORT_SOURCE_MAP[page] || V211_REPORT_SOURCE_MAP.dashboard;
  const element = elementMap[selected] || elementMap.Al;
  const compareSet = safeArray(compare, []).length ? compare.join(" + ") : selected;
  return {
    id: `${page}-${selected}-${Date.now()}`,
    sourcePage: page,
    sourceLabel: source.label,
    title: source.report,
    selectedElement: selected,
    selectedName: element?.name || selected,
    compareSet,
    summary: source.summary,
    includes: source.includes,
    generatedAt: new Date().toLocaleString(),
  };
}

function v211StoreReportIntent(intent) {
  if (typeof window === "undefined") return;
  try {
    const current = safeParseJSON(localStorage.getItem("elementos_report_pipeline"), []);
    const next = [intent, ...safeArray(current)].slice(0, 12);
    localStorage.setItem("elementos_report_pipeline", JSON.stringify(next));
    localStorage.setItem("elementos_pending_report", JSON.stringify(intent));
  } catch (_error) {
    // Best-effort only. Reporting should never crash the app.
  }
}

function V211ReportPipelineDock({ page, selected, compare, setPage }) {
  if (["landing", "login", "reports", "systemhealth", "publicdiscovery"].includes(page)) return null;
  const intent = v211ReportIntentForPage(page, selected, compare);
  const sendToReports = () => {
    v211StoreReportIntent(intent);
    setPage?.("reports");
  };
  return (
    <div className="rounded-[1.25rem] border border-cyan-300/[.12] bg-[#050b16]/88 p-3 shadow-[0_18px_60px_rgba(0,0,0,.22)] backdrop-blur-xl">
      <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
        <div className="min-w-0">
          <div className="text-[10px] font-black uppercase tracking-[.24em] text-cyan-200">Report pipeline · {intent.sourceLabel}</div>
          <div className="mt-1 text-sm leading-6 text-slate-300">
            Turn this page into a <b className="text-white">{intent.title}</b> for {intent.selectedName} / {intent.compareSet}.
          </div>
        </div>
        <div className="flex flex-wrap gap-2">
          <button type="button" onClick={sendToReports} className="rounded-xl border border-cyan-300/[.35] bg-cyan-300/10 px-4 py-2 text-sm font-black text-cyan-50 transition hover:bg-cyan-300/16">
            Generate Report
          </button>
          <button type="button" onClick={() => setPage?.("reports")} className="rounded-xl border border-white/10 bg-white/[0.035] px-4 py-2 text-sm font-black text-slate-200 transition hover:border-cyan-300/25">
            Research Centre
          </button>
        </div>
      </div>
    </div>
  );
}

function V211ResearchCentreHub({ compare = [], selected = "Al", isPro, startCheckout, setPage }) {
  const [pipeline, setPipeline] = useState([]);
  const [pending, setPending] = useState(null);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const list = safeParseJSON(localStorage.getItem("elementos_report_pipeline"), []);
    const latest = safeParseJSON(localStorage.getItem("elementos_pending_report"), null);
    setPipeline(safeArray(list));
    setPending(latest);
  }, []);

  const defaultIntent = pending || v211ReportIntentForPage("compare", selected, compare);
  const reportFamilies = [
    ["Mission Reports", "Mission Intelligence", "Decision-ready material recommendations from user goals and scenarios.", "dashboard"],
    ["Material Reports", "Element Explorer", "Single-element profile reports with applications, risks, pairings and future outlook.", "explorer"],
    ["Heatmap Reports", "Element Map", "Periodic heatmap and discovery-layer snapshots for all 118 elements.", "periodic"],
    ["Comparison Reports", "Compare", "Side-by-side material rankings, compatibility tables and recommendation notes.", "compare"],
    ["Forecast Reports", "Time Machine", "Future-state risk, environment and horizon reports.", "timemachine"],
    ["Interaction Reports", "Interaction Atlas", "Material response, pair behaviour, signal and anomaly reports.", "atlas"],
    ["Lab Reports", "Advanced Labs", "Particle collision, isotope, seismic and drilling lab reports.", "accelerator"],
    ["Saved Reports", "Research Centre", "Persistent cloud reports, share links and export history.", "reports"],
  ];

  const savePipelineSnapshot = () => {
    const intent = v211ReportIntentForPage("reports", selected, compare);
    v211StoreReportIntent({ ...intent, title: "Research Centre Snapshot", sourceLabel: "Reports" });
    setPipeline((items) => [{ ...intent, title: "Research Centre Snapshot", sourceLabel: "Reports" }, ...items].slice(0, 12));
  };

  return (
    <div className="space-y-5">
      <Panel className="overflow-hidden border-cyan-300/15 bg-[#030914]/[.95] p-0 shadow-[0_28px_120px_rgba(0,0,0,.35)]">
        <div className="relative grid gap-0 lg:grid-cols-[1.05fr_.95fr]">
          <div className="absolute inset-0 opacity-45" style={{ backgroundImage: "linear-gradient(rgba(34,211,238,.06) 1px, transparent 1px), linear-gradient(90deg, rgba(34,211,238,.06) 1px, transparent 1px)", backgroundSize: "72px 72px" }} />
          <div className="relative p-6 lg:p-8">
            <Pill gold><FileText size={12}/> unified research centre</Pill>
            <h1 className="mt-4 max-w-4xl text-5xl font-black tracking-tight lg:text-7xl">Reports are now the output engine.</h1>
            <p className="mt-5 max-w-3xl text-base leading-8 text-slate-300">
              Every core page now has a reporting path: Mission Intelligence, Explorer, Element Map, Compare, Time Machine, Interaction Atlas and Advanced Labs all feed into one professional Research Centre.
            </p>
            <div className="mt-6 grid gap-3 sm:grid-cols-3">
              {[["Active source", defaultIntent.sourceLabel], ["Report type", defaultIntent.title], ["Current set", defaultIntent.compareSet]].map(([label, value]) => (
                <div key={label} className="border border-cyan-300/[.12] bg-black/25 p-4">
                  <div className="text-[10px] font-black uppercase tracking-[.22em] text-slate-500">{label}</div>
                  <div className="mt-2 text-lg font-black text-cyan-50">{value}</div>
                </div>
              ))}
            </div>
            <div className="mt-6 flex flex-wrap gap-3">
              <Button variant="primary" onClick={savePipelineSnapshot}>Save Research Snapshot</Button>
              <Button onClick={() => setPage?.("timemachine")}>Open Forecast Source</Button>
              <Button onClick={() => setPage?.("accelerator")}>Open Lab Source</Button>
            </div>
          </div>
          <div className="relative border-t border-cyan-300/10 bg-black/20 p-6 lg:border-l lg:border-t-0 lg:p-8">
            <div className="text-xs font-black uppercase tracking-[.24em] text-cyan-200">Current report blueprint</div>
            <h2 className="mt-3 text-3xl font-black text-white">{defaultIntent.title}</h2>
            <p className="mt-3 text-sm leading-7 text-slate-300">{defaultIntent.summary}</p>
            <div className="mt-5 grid gap-2">
              {safeArray(defaultIntent.includes).map((item) => (
                <div key={item} className="flex items-center justify-between gap-3 border border-white/10 bg-slate-950/[.65] p-3 text-sm text-slate-200">
                  <span>{item}</span>
                  <span className="text-cyan-200">ready</span>
                </div>
              ))}
            </div>
            {!isPro && (
              <div className="mt-5 border border-amber-300/20 bg-amber-300/[.08] p-4 text-sm leading-6 text-amber-50">
                Export is the paid moment: preview reports free, unlock PDF/JSON/SVG and shareable exports with Pro Researcher.
                <button type="button" onClick={() => startCheckout?.("Pro Researcher")} className="mt-3 block rounded-xl border border-amber-200/30 bg-amber-200/10 px-4 py-2 text-sm font-black text-amber-50">Unlock exports</button>
              </div>
            )}
          </div>
        </div>
      </Panel>

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        {reportFamilies.map(([title, source, description, target]) => (
          <button key={title} type="button" onClick={() => target === "reports" ? null : setPage?.(target)} className="group border border-white/10 bg-[#07111f]/88 p-5 text-left shadow-[0_18px_60px_rgba(0,0,0,.2)] transition hover:-translate-y-1 hover:border-cyan-300/[.35] hover:bg-cyan-300/[.055]">
            <div className="text-[10px] font-black uppercase tracking-[.22em] text-slate-500">{source}</div>
            <div className="mt-3 text-2xl font-black text-white group-hover:text-cyan-50">{title}</div>
            <p className="mt-3 text-sm leading-6 text-slate-400">{description}</p>
            <div className="mt-5 text-xs font-black uppercase tracking-[.18em] text-cyan-200">open source →</div>
          </button>
        ))}
      </div>

      <Panel className="border-cyan-300/[.12] bg-[#050b16]/90">
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div>
            <Pill><Save size={12}/> report intake queue</Pill>
            <h2 className="mt-3 text-3xl font-black">Reports generated from across ElementOS</h2>
            <p className="mt-2 text-sm leading-6 text-slate-400">This queue shows report intents pushed from Explorer, Map, Compare, Time Machine and Labs before cloud save/export.</p>
          </div>
          <Button onClick={savePipelineSnapshot}>Add current page snapshot</Button>
        </div>
        <div className="mt-5 grid gap-3 lg:grid-cols-3">
          {(pipeline.length ? pipeline : [defaultIntent]).slice(0, 6).map((item, index) => (
            <div key={item.id || `${item.title}-${index}`} className="border border-white/10 bg-black/25 p-4">
              <div className="text-[10px] font-black uppercase tracking-[.2em] text-cyan-200">{item.sourceLabel}</div>
              <div className="mt-2 text-lg font-black text-white">{item.title}</div>
              <p className="mt-2 line-clamp-3 text-sm leading-6 text-slate-400">{item.summary}</p>
              <div className="mt-3 text-xs text-slate-500">{item.generatedAt}</div>
            </div>
          ))}
        </div>
      </Panel>
    </div>
  );
}


function ParticleAcceleratorLab({ setPage, setSelected, setCompare, setForecastRequest }) {
  const machines = [
    { id: "linac", name: "LINAC", subtitle: "RF cavity beamline", shape: "linear", multiplier: 0.75, focus: "Straight-line acceleration through synchronized RF cavities." },
    { id: "cyclotron", name: "Cyclotron", subtitle: "Spiral magnetic confinement", shape: "spiral", multiplier: 0.52, focus: "Magnetic bending drives a widening spiral orbit." },
    { id: "synchrotron", name: "Synchrotron", subtitle: "Timed RF ring", shape: "ring", multiplier: 1.15, focus: "Magnetic ramping and RF timing keep the bunch locked to the ring." },
    { id: "storage", name: "Storage Ring", subtitle: "Long-life beam orbit", shape: "ring", multiplier: 0.92, focus: "Orbit lifetime, vacuum quality and beam loss dominate the run." },
    { id: "hadron", name: "Hadron Collider", subtitle: "Counter-rotating beams", shape: "collider", multiplier: 2.8, focus: "Two high-energy beams collide at interaction points to produce event signatures." },
    { id: "electron", name: "Electron Collider", subtitle: "Lepton precision ring", shape: "collider", multiplier: 1.65, focus: "Fast electron beams produce clean events but stronger radiation loss." },
    { id: "ion", name: "Ion Accelerator", subtitle: "Heavy nucleus beam", shape: "ring", multiplier: 1.38, focus: "Heavy ions raise target yield, activation risk and detector complexity." },
    { id: "wakefield", name: "Plasma Wakefield", subtitle: "Compact wave tunnel", shape: "wakefield", multiplier: 3.2, focus: "A plasma wave accelerates charged packets through a compact tunnel." },
    { id: "fixed", name: "Fixed Target", subtitle: "Beam into material slab", shape: "target", multiplier: 0.88, focus: "Beam energy is deposited into a selected target material." },
    { id: "medical", name: "Medical Beamline", subtitle: "Therapy / isotope beam", shape: "target", multiplier: 0.46, focus: "Dose precision, stability and controlled target interaction dominate." },
  ];

  const particles = ["Proton", "Electron", "Neutron", "Alpha", "Element Ion", "Custom Nucleus"];
  const [machineId, setMachineId] = useState("hadron");
  const [particle, setParticle] = useState("Proton");
  const [beamSymbol, setBeamSymbol] = useState("H");
  const [targetSymbol, setTargetSymbol] = useState("W");
  const [beamEnergy, setBeamEnergy] = useState(78);
  const [magneticField, setMagneticField] = useState(64);
  const [rfFrequency, setRfFrequency] = useState(72);
  const [vacuum, setVacuum] = useState(86);
  const [detectorSensitivity, setDetectorSensitivity] = useState(74);
  const [collimation, setCollimation] = useState(67);
  const [beamCurrent, setBeamCurrent] = useState(58);
  const [pulseRate, setPulseRate] = useState(44);
  const [simulationRunning, setSimulationRunning] = useState(false);
  const [collisionResult, setCollisionResult] = useState(null);
  const [selectedEvent, setSelectedEvent] = useState("Collision vertex");

  const machine = machines.find((item) => item.id === machineId) || machines[0];
  const beamElement = elementMap[beamSymbol] || elementMap.H || elements[0];
  const targetElement = elementMap[targetSymbol] || elementMap.W || elementMap.Al;
  const beamScore = score(beamElement.symbol);
  const targetScore = score(targetElement.symbol);
  const isCollider = machine.shape === "collider";
  const isTarget = machine.shape === "target";
  const ionMass = particle === "Element Ion" || particle === "Custom Nucleus" ? Math.max(1, beamElement.atomicNumber / 12) : 1;
  const particleMassFactor = particle === "Electron" ? 0.18 : particle === "Alpha" ? 1.65 : particle === "Neutron" ? 1.05 : particle === "Element Ion" ? 1 + ionMass * 0.18 : particle === "Custom Nucleus" ? 1.9 : 1;
  const chargeFactor = particle === "Electron" ? 1 : particle === "Neutron" ? 0.35 : particle === "Alpha" ? 2 : particle === "Element Ion" ? Math.max(1, Math.min(8, Math.round(beamElement.atomicNumber / 14))) : 1;
  const beamEnergyGeV = Math.max(0.02, Number(((beamEnergy / 100) * machine.multiplier * particleMassFactor * 120).toFixed(2)));
  const collisionEnergyGeV = Number((beamEnergyGeV * (isCollider ? 2 : 1)).toFixed(2));
  const velocityFraction = Math.max(0.02, Math.min(0.999, 1 - 1 / (1 + beamEnergyGeV / Math.max(0.18, particleMassFactor * 1.6))));
  const velocityMS = Math.round(velocityFraction * 299792458);
  const accelerationMS2 = Math.round((rfFrequency / 100) * (beamEnergy / 100) * machine.multiplier * 8.7e13);
  const magneticTesla = Number((0.12 + (magneticField / 100) * 14.8).toFixed(2));
  const rfMHz = Number((36 + rfFrequency * 11.7).toFixed(1));
  const orbitRadiusM = Number(Math.max(0.6, (beamEnergyGeV / Math.max(0.12, 0.3 * magneticTesla * chargeFactor))).toFixed(2));
  const vacuumPressure = Number((Math.pow(10, -6 - vacuum / 20)).toExponential(2));
  const beamPowerMW = Number(((beamEnergyGeV * beamCurrent * pulseRate) / 10000).toFixed(2));
  const beamStability = Math.max(8, Math.min(99, Math.round(vacuum * 0.28 + magneticField * 0.2 + rfFrequency * 0.18 + collimation * 0.22 + detectorSensitivity * 0.08 - (beamEnergy > 90 ? 8 : 0) - (beamCurrent > 88 ? 5 : 0))));
  const luminosity = Math.max(6, Math.min(99, Math.round(beamEnergy * 0.3 + rfFrequency * 0.16 + detectorSensitivity * 0.18 + beamCurrent * 0.14 + magneticField * 0.12 + (isCollider ? 13 : -5))));
  const targetYield = Math.max(8, Math.min(99, Math.round(targetScore.pressure * 8 + targetScore.thermal * 7 + beamEnergy * 0.16 + detectorSensitivity * 0.12 + (isTarget ? 15 : 4))));
  const scatteringIndex = Math.max(4, Math.min(99, Math.round(targetElement.atomicNumber * 0.58 + beamEnergy * 0.22 + chargeFactor * 4)));
  const radiationLoad = Math.max(4, Math.min(99, Math.round(beamEnergy * 0.36 + targetScore.rarity * 7 + particleMassFactor * 8 + beamCurrent * 0.12 - vacuum * 0.07)));
  const heatLoad = Math.max(4, Math.min(99, Math.round(beamPowerMW * 9 + targetScore.thermal * 6 + beamEnergy * 0.13 + beamCurrent * 0.18)));
  const activationRisk = Math.max(3, Math.min(99, Math.round(targetElement.atomicNumber * 0.52 + radiationLoad * 0.25 + particleMassFactor * 6)));
  const efficiency = Math.max(7, Math.min(99, Math.round((beamStability + luminosity + targetYield) / 3 - radiationLoad * 0.11 + vacuum * 0.07)));
  const collisionQuality = Math.max(5, Math.min(99, Math.round(luminosity * 0.35 + beamStability * 0.25 + detectorSensitivity * 0.2 + collimation * 0.2)));

  const resultHeadline = collisionQuality > 82 ? "High-confidence collision signature" : collisionQuality > 62 ? "Controlled interaction event" : "Unstable low-yield interaction";
  const resultProducts = isCollider
    ? ["Jet signature", "Muon trace", "Gamma burst", "Energy deposition"]
    : isTarget
    ? ["Scattering cone", "Thermal plume", "Activation signal", "Isotope yield"]
    : machine.shape === "wakefield"
    ? ["Wake crest", "Electron packet", "Field collapse", "Energy surge"]
    : ["RF gain", "Orbit trim", "Beam focus", "Extraction pulse"];

  const warnings = [
    radiationLoad > 76 ? "Radiation load elevated — shielding review required." : "Radiation envelope inside simulated tolerance.",
    beamStability < 58 ? "Beam instability risk — improve vacuum, collimation or RF timing." : "Beam orbit stable across current configuration.",
    magneticField > 86 ? "Magnet load high — cryogenic and coil limits should be checked." : "Magnet load nominal.",
    heatLoad > 78 ? "Target heat load high — reduce current or improve cooling." : "Target thermal envelope acceptable.",
    detectorSensitivity > 90 && luminosity > 82 ? "Detector saturation possible at current luminosity." : "Detector window clean."
  ];

  const eventSignatures = isCollider
    ? ["Opposing beam lock", "Collision vertex", "Muon trace", "Hadronic jet", "Gamma burst", "Detector yield"]
    : isTarget
    ? ["Beam strike", "Thermal plume", "Scattering cone", "Activation signal", "Isotope yield", "Target fatigue"]
    : machine.shape === "wakefield"
    ? ["Plasma wave crest", "Electron packet", "Wake tunnel", "Field collapse", "Energy surge", "Beam extraction"]
    : ["Injector pulse", "RF cavity gain", "Magnet correction", "Orbit trim", "Beam focus", "Extraction line"];

  const particlePackets = Array.from({ length: simulationRunning ? 18 : 8 }, (_, index) => ({
    id: index,
    delay: Number((index * 0.28).toFixed(2)),
    size: 5 + (index % 4) * 2,
    energy: Math.max(12, Math.min(99, Math.round(beamEnergy * 0.55 + rfFrequency * 0.22 + index * 2))),
  }));

  const detectorHits = Array.from({ length: 16 }, (_, index) => ({
    id: index,
    angle: index * 22.5 + (simulationRunning ? 12 : 0),
    strength: Math.max(8, Math.min(99, Math.round(collisionQuality * 0.58 + detectorSensitivity * 0.24 + ((index * 13) % 24)))),
  }));

  const collisionDataRows = [
    ["Machine mode", machine.name, machine.focus],
    ["Beam source", `${beamElement.name} (${beamElement.symbol})`, `Atomic number ${beamElement.atomicNumber}`],
    ["Collision target", `${targetElement.name} (${targetElement.symbol})`, `Atomic number ${targetElement.atomicNumber}`],
    ["Particle stream", particle, `Charge factor ${chargeFactor.toFixed ? chargeFactor.toFixed(2) : chargeFactor}`],
    ["Beam energy", `${beamEnergyGeV} GeV`, `${collisionEnergyGeV} GeV collision energy`],
    ["Speed", `${velocityMS.toLocaleString()} m/s`, `${(velocityFraction * 100).toFixed(3)}% of light speed`],
    ["Acceleration", `${accelerationMS2.toExponential(3)} m/s²`, "RF-driven simulated beam acceleration"],
    ["Magnetism", `${magneticTesla} Tesla`, `Orbit radius ${orbitRadiusM} m`],
    ["RF system", `${rfMHz} MHz`, `Pulse rate ${pulseRate}% · beam current ${beamCurrent}%`],
    ["Vacuum", `${vacuumPressure} Torr`, `${vacuum}% vacuum quality`],
    ["Luminosity", `${luminosity}%`, "Collision/event density estimate"],
    ["Detector confidence", `${detectorSensitivity}%`, `${selectedEvent} selected`],
    ["Scattering index", `${scatteringIndex}%`, "Target interaction spread"],
    ["Activation risk", `${activationRisk}%`, "Simulated induced target activity"],
    ["Thermal load", `${heatLoad}%`, `${beamPowerMW} MW beam power`],
  ];

  const eventLogRows = [
    ["00:00", "Injector armed", `${particle} stream prepared from ${beamElement.symbol}`],
    ["00:02", "Vacuum check", `${vacuumPressure} Torr beamline pressure confirmed`],
    ["00:04", "RF phase lock", `${rfMHz} MHz synchronized across acceleration sequence`],
    ["00:06", "Magnet ramp", `${magneticTesla} T field stabilized around ${machine.name}`],
    ["00:09", "Beam focus", `${collimation}% collimation · ${beamStability}% stability`],
    ["00:12", isCollider ? "Interaction point crossed" : isTarget ? "Target strike recorded" : "Extraction line opened", `${resultHeadline} · ${collisionQuality}% quality`],
    ["00:15", "Detector readout", `${resultProducts.join(" · ")}`],
  ];

  const beamTelemetryRows = [
    ["Speed", `${velocityMS.toLocaleString()} m/s`, `${(velocityFraction * 100).toFixed(3)}% of light`, Math.round(velocityFraction * 100)],
    ["Acceleration", `${accelerationMS2.toExponential(3)} m/s²`, "RF-driven simulated acceleration", Math.min(99, Math.round(beamEnergy * 0.52 + rfFrequency * 0.28))],
    ["Magnetism", `${magneticTesla} T`, `Orbit radius ${orbitRadiusM} m`, magneticField],
    ["RF Sync", `${rfMHz} MHz`, `${pulseRate}% pulse · ${beamCurrent}% current`, rfFrequency],
    ["Beam Power", `${beamPowerMW} MW`, "Estimated delivered beam power", Math.min(99, Math.round(beamPowerMW * 11))],
    ["Luminosity", `${luminosity}%`, "Event density estimate", luminosity],
  ];

  const targetResponseRows = [
    ["Heat Load", `${heatLoad}%`, `${targetElement.symbol} thermal envelope`, heatLoad],
    ["Activation Risk", `${activationRisk}%`, "Induced target activity", activationRisk],
    ["Scattering", `${scatteringIndex}%`, "Angular spread / interaction cone", scatteringIndex],
    ["Target Yield", `${targetYield}%`, "Useful event or isotope yield", targetYield],
    ["Damage Index", `${Math.max(5, Math.min(99, Math.round((heatLoad + radiationLoad + activationRisk) / 3)))}%`, "Combined material stress", Math.max(5, Math.min(99, Math.round((heatLoad + radiationLoad + activationRisk) / 3)))],
    ["Penetration", `${Math.max(4, Math.min(99, Math.round(beamEnergy * 0.46 + targetScore.pressure * 8)))}%`, "Beam depth estimate", Math.max(4, Math.min(99, Math.round(beamEnergy * 0.46 + targetScore.pressure * 8)))],
  ];

  const detectorOutputRows = [
    ["Muon Trace", `${Math.max(1, Math.round(collisionQuality * 0.42 + detectorSensitivity * 0.18))}`, "Track candidates", Math.max(6, Math.min(99, Math.round(collisionQuality * 0.55 + detectorSensitivity * 0.18)))],
    ["Gamma Burst", `${Math.max(2, Math.round(radiationLoad * 0.72))}`, "Photon burst signature", radiationLoad],
    ["Neutron Flux", `${Math.max(1, Math.round(scatteringIndex * 0.64))}`, "Secondary neutron signal", scatteringIndex],
    ["Energy Deposition", `${Math.max(4, Math.min(99, Math.round(heatLoad * 0.55 + beamEnergy * 0.25)))}%`, "Detector calorimeter load", Math.max(4, Math.min(99, Math.round(heatLoad * 0.55 + beamEnergy * 0.25)))],
    ["Saturation", `${Math.max(3, Math.min(99, Math.round(luminosity * 0.45 + detectorSensitivity * 0.35)))}%`, "Readout saturation risk", Math.max(3, Math.min(99, Math.round(luminosity * 0.45 + detectorSensitivity * 0.35)))],
    ["Confidence", `${detectorSensitivity}%`, `${selectedEvent} readout selected`, detectorSensitivity],
  ];

  const collisionResultRows = [
    ["Event Type", resultHeadline, "Primary simulated outcome", collisionQuality],
    ["Products", resultProducts.join(" · "), "Detected final-state signature", Math.max(8, Math.min(99, resultProducts.length * 16))],
    ["Quality", `${collisionQuality}%`, "Interaction clarity", collisionQuality],
    ["Efficiency", `${efficiency}%`, "Useful output vs load", efficiency],
    ["Stability", `${beamStability}%`, "Beam control quality", beamStability],
    ["Risk Envelope", radiationLoad > 76 || heatLoad > 78 ? "Elevated" : "Controlled", "Radiation and thermal risk", Math.max(radiationLoad, heatLoad)],
  ];

  const collisionMatrixRows = [
    ["Energy", collisionQuality, `${collisionEnergyGeV} GeV collision`],
    ["Yield", targetYield, `${targetElement.symbol} target response`],
    ["Damage", Math.max(5, Math.min(99, Math.round((heatLoad + activationRisk) / 2))), "Thermal + activation load"],
    ["Activation", activationRisk, "Induced material activity"],
    ["Confidence", detectorSensitivity, "Detector readout quality"],
  ];

  const sequence = [
    ["Inject", Math.round(beamEnergy * 0.35 + vacuum * 0.18 + beamCurrent * 0.12)],
    ["Accelerate", Math.round(beamEnergy * 0.64 + rfFrequency * 0.2 + pulseRate * 0.08)],
    ["Magnetize", Math.round(magneticField * 0.74 + collimation * 0.12)],
    ["Focus", Math.round(collimation * 0.68 + vacuum * 0.14 + detectorSensitivity * 0.08)],
    [isCollider ? "Collide" : isTarget ? "Strike" : "Extract", isCollider ? collisionQuality : targetYield],
  ];

  const runSimulation = () => {
    setSimulationRunning(true);
    const next = {
      id: `${machine.id}-${beamElement.symbol}-${targetElement.symbol}-${Date.now()}`,
      headline: resultHeadline,
      machine: machine.name,
      beam: particle === "Element Ion" || particle === "Custom Nucleus" ? `${beamElement.name} ${particle}` : particle,
      target: targetElement.name,
      collisionEnergyGeV,
      velocityMS,
      velocityFraction,
      accelerationMS2,
      magneticTesla,
      rfMHz,
      beamPowerMW,
      orbitRadiusM,
      collisionQuality,
      radiationLoad,
      heatLoad,
      activationRisk,
      scatteringIndex,
      products: resultProducts,
      summary: `${machine.name} simulated ${particle === "Element Ion" || particle === "Custom Nucleus" ? beamElement.name : particle} beam interaction with ${targetElement.name}. Collision quality ${collisionQuality}%, radiation load ${radiationLoad}%, target yield ${targetYield}%.`,
    };
    setCollisionResult(next);
    setSelectedEvent(resultProducts[0] || eventSignatures[0]);
    showToast("Particle Accelerator simulation running.");
  };

  const stopSimulation = () => {
    setSimulationRunning(false);
    showToast("Particle Accelerator simulation stopped.");
  };

  const saveReport = () => {
    exportAllFormats({
      baseName: "elementos-particle-accelerator-report",
      title: "ElementOS Particle Accelerator Lab Report",
      summary: collisionResult?.summary || `${machine.name} · ${particle} beam into ${targetElement.name} · stability ${beamStability}% · collision quality ${collisionQuality}% · target yield ${targetYield}%`,
      payload: { machine: machine.name, particle, beamElement, targetElement, beamEnergy, beamEnergyGeV, collisionEnergyGeV, velocityMS, velocityFraction, accelerationMS2, magneticTesla, rfMHz, vacuumPressure, beamCurrent, beamPowerMW, rfFrequency, vacuum, detectorSensitivity, collimation, beamStability, luminosity, targetYield, scatteringIndex, radiationLoad, heatLoad, activationRisk, efficiency, collisionQuality, warnings, collisionResult },
      sections: [
        ["Machine", `${machine.name} — ${machine.focus}`],
        ["Beam Setup", `${particle} beam, ${beamElement.symbol} source, ${targetElement.symbol} target, ${beamEnergyGeV} GeV beam energy, ${collisionEnergyGeV} GeV collision energy.`],
        ["Motion Data", `Velocity ${velocityMS.toLocaleString()} m/s (${(velocityFraction * 100).toFixed(2)}% c). Acceleration ${accelerationMS2.toExponential(2)} m/s². Orbit radius ${orbitRadiusM} m.`],
        ["Magnetism / RF", `Magnetic field ${magneticTesla} T. RF ${rfMHz} MHz. Vacuum pressure ${vacuumPressure} Torr.`],
        ["Collision Result", `${resultHeadline}. Products: ${resultProducts.join(", ")}.`],
        ["Warnings", warnings.join("\n")]
      ]
    });
  };

  const sendTargetToExplorer = () => {
    setSelected?.(targetElement.symbol);
    setPage?.("explorer");
  };
  const compareTargetMaterials = () => {
    setCompare?.([beamElement.symbol, targetElement.symbol, "Ti", "W"].filter(Boolean).slice(0, 4));
    setPage?.("compare");
  };
  const forecastTarget = () => {
    setForecastRequest?.({ material: targetElement.symbol, years: 25, environment: "Accelerator target exposure", source: "Particle Accelerator Lab" });
    setPage?.("timemachine");
  };

  const ParticleMotionOverlay = () => (
    <div className="pointer-events-none absolute inset-0 z-10 overflow-hidden">
      {machine.shape === "linear" || machine.shape === "target" || machine.shape === "wakefield" ? (
        <div className="absolute inset-x-10 top-1/2 h-32 -translate-y-1/2">
          {particlePackets.map((packet) => (
            <div
              key={`packet-${packet.id}`}
              className={`absolute top-1/2 rounded-full bg-cyan-100 shadow-[0_0_26px_rgba(34,211,238,.95)] ${simulationRunning ? "animate-pulse" : ""}`}
              style={{
                left: `${simulationRunning ? (packet.id * 7 + 5) % 92 : 12 + packet.id * 8}%`,
                width: packet.size,
                height: packet.size,
                transform: "translate(-50%, -50%)",
                opacity: simulationRunning ? 0.95 : 0.38,
                transition: "left 650ms linear, opacity 250ms ease",
              }}
            />
          ))}
          <div className="absolute left-0 top-1/2 h-px w-full -translate-y-1/2 bg-gradient-to-r from-transparent via-cyan-100/70 to-transparent shadow-[0_0_40px_rgba(34,211,238,.55)]" />
        </div>
      ) : (
        <div className="absolute left-1/2 top-1/2 h-[520px] w-[520px] -translate-x-1/2 -translate-y-1/2">
          {particlePackets.map((packet) => {
            const angle = (packet.id / particlePackets.length) * Math.PI * 2 + (simulationRunning ? packet.id * 0.35 : 0);
            const radius = 160 + (packet.id % 3) * 36;
            const x = 260 + Math.cos(angle) * radius;
            const y = 260 + Math.sin(angle) * radius;
            return (
              <div
                key={`orbit-packet-${packet.id}`}
                className="absolute rounded-full bg-cyan-100 shadow-[0_0_30px_rgba(34,211,238,.95)]"
                style={{ left: x, top: y, width: packet.size, height: packet.size, transform: "translate(-50%, -50%)", opacity: simulationRunning ? 0.95 : 0.42, transition: "left 520ms linear, top 520ms linear" }}
              />
            );
          })}
          {isCollider && particlePackets.slice(0, 10).map((packet) => {
            const angle = -(packet.id / 10) * Math.PI * 2 - (simulationRunning ? packet.id * 0.45 : 0);
            const radius = 205;
            const x = 260 + Math.cos(angle) * radius;
            const y = 260 + Math.sin(angle) * radius;
            return <div key={`counter-${packet.id}`} className="absolute h-2 w-2 rounded-full bg-amber-100 shadow-[0_0_30px_rgba(251,191,36,.95)]" style={{ left: x, top: y, transform: "translate(-50%, -50%)", opacity: simulationRunning ? 0.95 : 0.4, transition: "left 520ms linear, top 520ms linear" }} />;
          })}
        </div>
      )}
      <div className="absolute left-1/2 top-1/2 h-72 w-72 -translate-x-1/2 -translate-y-1/2 rounded-full border border-cyan-300/[.12]" />
      <div className="absolute left-1/2 top-1/2 h-96 w-96 -translate-x-1/2 -translate-y-1/2 rounded-full border border-amber-300/10" />
      {simulationRunning && (
        <div className="absolute left-1/2 top-1/2 h-24 w-24 -translate-x-1/2 -translate-y-1/2 rounded-full bg-amber-200/15 blur-xl shadow-[0_0_90px_rgba(251,191,36,.55)]" />
      )}
    </div>
  );

  const DetectorHalo = () => (
    <div className="pointer-events-none absolute inset-0 z-0">
      <div className="absolute left-1/2 top-1/2 h-[620px] w-[620px] -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/5" />
      <div className="absolute left-1/2 top-1/2 h-[700px] w-[700px] -translate-x-1/2 -translate-y-1/2 rounded-full border border-cyan-300/8" />
      {detectorHits.map((hit) => (
        <div
          key={`hit-${hit.id}`}
          className="absolute left-1/2 top-1/2 h-1.5 w-8 origin-left bg-gradient-to-r from-cyan-200/[.75] to-transparent shadow-[0_0_20px_rgba(34,211,238,.55)]"
          style={{ transform: `rotate(${hit.angle}deg) translateX(${250 + (hit.id % 3) * 38}px)`, opacity: simulationRunning ? hit.strength / 100 : 0.18 }}
        />
      ))}
    </div>
  );

  const BeamLine = () => {
    const beamLabel = particle === "Element Ion" || particle === "Custom Nucleus" ? beamElement.symbol : particle.slice(0, 2).toUpperCase();
    if (machine.shape === "linear") {
      return (
        <div className="absolute inset-x-8 top-1/2 h-36 -translate-y-1/2 border-y border-cyan-300/20 bg-cyan-300/[.035]">
          <div className={`absolute left-0 top-1/2 h-[3px] -translate-y-1/2 bg-cyan-200 shadow-[0_0_48px_rgba(34,211,238,.95)] ${simulationRunning ? "w-full" : "w-[72%]"}`} />
          {Array.from({ length: 13 }).map((_, i) => (
            <div key={i} className="absolute top-1/2 h-32 w-8 -translate-y-1/2 border border-cyan-300/25 bg-black/[.55] shadow-[0_0_30px_rgba(34,211,238,.18)]" style={{ left: `${4 + i * 7.3}%` }}>
              <div className="absolute inset-x-2 top-2 h-3 bg-cyan-300/20" />
              <div className="absolute inset-x-2 bottom-2 h-3 bg-cyan-300/20" />
            </div>
          ))}
          <div className="absolute left-4 top-1/2 -translate-y-1/2 border border-cyan-100/[.35] bg-cyan-300/15 px-3 py-2 text-xs font-black text-cyan-50">{beamLabel}</div>
          <div className="absolute right-4 top-1/2 h-24 w-7 -translate-y-1/2 bg-amber-300/25 shadow-[0_0_55px_rgba(251,191,36,.45)]" />
        </div>
      );
    }
    if (machine.shape === "target") {
      return (
        <div className="absolute inset-x-10 top-1/2 h-60 -translate-y-1/2">
          <div className="absolute left-0 top-1/2 h-3 w-[62%] -translate-y-1/2 bg-cyan-200 shadow-[0_0_52px_rgba(34,211,238,.95)]" />
          <div className="absolute left-5 top-[42%] border border-cyan-100/[.35] bg-cyan-300/15 px-3 py-2 text-xs font-black text-cyan-50">{beamLabel} beam</div>
          <div className="absolute left-[62%] top-1/2 h-px w-[22%] -translate-y-1/2 bg-gradient-to-r from-amber-200 to-transparent shadow-[0_0_50px_rgba(251,191,36,.7)]" />
          <div className="absolute right-[18%] top-1/2 flex h-64 w-14 -translate-y-1/2 items-center justify-center border border-amber-200/[.35] bg-amber-300/18 text-lg font-black text-amber-50 shadow-[0_0_90px_rgba(251,191,36,.5)]">{targetElement.symbol}</div>
          {Array.from({ length: 14 }).map((_, i) => (
            <div key={i} className="absolute h-px w-32 origin-left bg-amber-100/[.35]" style={{ left: "72%", top: "50%", transform: `rotate(${-54 + i * 8}deg)` }} />
          ))}
          <div className="absolute right-[7%] top-1/2 h-72 w-72 -translate-y-1/2 rounded-full border border-amber-200/20 bg-amber-300/[.045] blur-sm" />
        </div>
      );
    }
    if (machine.shape === "wakefield") {
      return (
        <div className="absolute inset-x-10 top-1/2 h-72 -translate-y-1/2 overflow-hidden border border-violet-300/20 bg-violet-300/[.035]">
          {Array.from({ length: 11 }).map((_, i) => (
            <div key={i} className="absolute top-1/2 h-40 w-40 -translate-y-1/2 rounded-full border border-fuchsia-200/25" style={{ left: `${-8 + i * 10}%`, transform: `translateY(-50%) scale(${1 + (i % 3) * 0.16})` }} />
          ))}
          <div className="absolute left-0 top-1/2 h-2 w-full -translate-y-1/2 bg-gradient-to-r from-cyan-200 via-fuchsia-200 to-transparent shadow-[0_0_60px_rgba(217,70,239,.75)]" />
          <div className="absolute left-[58%] top-1/2 h-6 w-6 -translate-y-1/2 rounded-full bg-white shadow-[0_0_45px_rgba(255,255,255,.9)]" />
        </div>
      );
    }
    return (
      <div className="absolute left-1/2 top-1/2 h-[460px] w-[460px] -translate-x-1/2 -translate-y-1/2">
        {[0, 1, 2].map((ring) => (
          <div key={ring} className="absolute inset-0 rounded-full border border-cyan-300/20 shadow-[0_0_80px_rgba(34,211,238,.08)]" style={{ transform: `scale(${1 - ring * 0.14}) rotate(${ring * 18}deg)` }} />
        ))}
        <div className="absolute inset-[18%] rounded-full border border-amber-200/20 bg-cyan-300/[.035]" />
        <div className="absolute left-1/2 top-0 h-full w-px -translate-x-1/2 bg-cyan-300/15" />
        <div className="absolute left-0 top-1/2 h-px w-full -translate-y-1/2 bg-cyan-300/15" />
        <div className={`absolute left-1/2 top-1/2 h-3 w-3 -translate-x-1/2 -translate-y-1/2 rounded-full bg-cyan-100 shadow-[0_0_46px_rgba(34,211,238,.95)] ${simulationRunning ? "animate-pulse" : ""}`} />
        {isCollider && <div className="absolute left-1/2 top-1/2 h-5 w-5 -translate-x-1/2 -translate-y-1/2 rounded-full bg-amber-200 shadow-[0_0_70px_rgba(251,191,36,.9)]" />}
        <div className="absolute left-1/2 top-4 -translate-x-1/2 border border-cyan-100/25 bg-black/45 px-3 py-1 text-xs font-black text-cyan-50">{beamElement.symbol} beam</div>
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 border border-amber-100/25 bg-black/45 px-3 py-1 text-xs font-black text-amber-50">{targetElement.symbol} target</div>
      </div>
    );
  };

  return (
    <div className="eos-v218-accelerator space-y-6">
      <PageHero
        eyebrow="Advanced Lab · Particle Accelerator"
        pill="Beam physics simulator"
        title={<>Particle <span className="bg-gradient-to-r from-cyan-200 via-white to-amber-200 bg-clip-text text-transparent">Accelerator Lab</span></>}
        description="Simulate accelerator modes, particle beams, magnetic steering, RF acceleration, 118-element collision targets, target response and detector event output."
        actions={[
          { label: simulationRunning ? "Stop Simulation" : "Start Simulation", onClick: simulationRunning ? stopSimulation : runSimulation, primary: true },
          { label: "Export Accelerator Report", onClick: saveReport },
        ]}
      />

      <ElementOSIntelligenceLayer page="accelerator" context={{ selected: beamElement.symbol }} setPage={setPage} />

      <div className="grid gap-3 md:grid-cols-4">
        {[
          ["Machine", machine.name, machine.subtitle],
          ["Beam", `${beamElement.symbol} → ${targetElement.symbol}`, `${particle} collision path`],
          ["Energy", `${collisionEnergyGeV} GeV`, `${(velocityFraction * 100).toFixed(2)}% light speed`],
          ["State", simulationRunning ? "Running" : "Ready", `${collisionQuality}% collision quality`],
        ].map(([label, value, note]) => (
          <div key={label} className="border border-cyan-300/[.12] bg-[#050b16]/80 p-4 shadow-[inset_0_1px_0_rgba(255,255,255,.04)]">
            <div className="text-[10px] font-black uppercase tracking-[.2em] text-slate-500">{label}</div>
            <div className="mt-2 text-xl font-black text-white">{value}</div>
            <div className="mt-1 text-xs leading-5 text-slate-400">{note}</div>
          </div>
        ))}
      </div>

      <div className="grid gap-6 xl:grid-cols-[280px_minmax(0,1fr)_340px]">
        <Panel className="border-cyan-300/15 bg-[#050b16]/90 shadow-[0_24px_80px_rgba(0,0,0,.28)]">
          <Pill><Zap size={12}/> accelerator modes</Pill>
          <p className="mt-3 text-xs leading-5 text-slate-400">Choose the machine geometry first. The centre chamber, telemetry and collision output adapt without changing the rest of the lab.</p>
          <div className="mt-4 grid gap-2">
            {machines.map((item) => (
              <button key={item.id} onClick={() => setMachineId(item.id)} className={`group border p-4 text-left transition hover:-translate-y-0.5 ${machineId === item.id ? "border-cyan-300/[.55] bg-cyan-300/[.12] shadow-[0_0_32px_rgba(34,211,238,.14)]" : "border-white/10 bg-black/[.22] hover:border-cyan-300/25 hover:bg-cyan-300/[.06]"}`}>
                <div className="flex items-center justify-between gap-3">
                  <div><div className="text-sm font-black text-white">{item.name}</div><div className="mt-1 text-[11px] text-slate-500">{item.subtitle}</div></div>
                  <div className="h-8 w-1 bg-cyan-300/45" />
                </div>
              </button>
            ))}
          </div>
        </Panel>

        <Panel className="overflow-hidden border-cyan-300/15 bg-[#030914]/[.95] p-0 shadow-[0_28px_120px_rgba(0,0,0,.35)]">
          <div className="relative min-h-[690px] overflow-hidden border border-cyan-300/10 bg-[linear-gradient(rgba(34,211,238,.06)_1px,transparent_1px),linear-gradient(90deg,rgba(34,211,238,.06)_1px,transparent_1px),radial-gradient(circle_at_50%_44%,rgba(34,211,238,.18),transparent_34%),linear-gradient(135deg,#020617,#061120_65%,#020617)] bg-[size:64px_64px,64px_64px,auto,auto]">
            <div className="absolute inset-0 pointer-events-none">
              <div className="absolute left-1/2 top-0 h-full w-px bg-cyan-300/[.12]" />
              <div className="absolute left-0 top-1/2 h-px w-full bg-cyan-300/[.12]" />
              <div className="absolute left-[12%] top-[18%] h-2 w-2 bg-cyan-200 shadow-[0_0_24px_rgba(34,211,238,.9)]" />
              <div className="absolute right-[14%] bottom-[16%] h-2 w-2 bg-amber-200 shadow-[0_0_24px_rgba(251,191,36,.8)]" />
              {simulationRunning && <div className="absolute inset-0 bg-cyan-300/[.04] animate-pulse" />}
            </div>
            <div className="absolute left-6 top-6 z-20 max-w-[440px] border border-cyan-300/20 bg-black/[.55] px-5 py-4 backdrop-blur-xl shadow-[0_18px_50px_rgba(0,0,0,.32)]">
              <div className="text-[10px] font-black uppercase tracking-[.22em] text-slate-500">active accelerator</div>
              <div className="mt-1 text-3xl font-black text-white md:text-4xl">{machine.name}</div>
              <div className="text-sm text-cyan-100">{particle === "Element Ion" || particle === "Custom Nucleus" ? beamElement.name : particle} → {targetElement.name}</div>
              <div className="mt-2 max-w-sm text-xs leading-5 text-slate-400">{machine.focus}</div>
            </div>
            <div className="absolute right-6 top-6 z-20 flex flex-wrap gap-2 rounded-none border border-cyan-300/15 bg-black/[.35] p-2 backdrop-blur-xl">
              <button onClick={simulationRunning ? stopSimulation : runSimulation} className={`border px-4 py-3 text-sm font-black shadow-[0_0_24px_rgba(34,211,238,.12)] ${simulationRunning ? "border-amber-300/50 bg-amber-300/[.12] text-amber-50 hover:bg-amber-300/18" : "border-cyan-300/[.35] bg-cyan-300/10 text-cyan-50 hover:bg-cyan-300/18"}`}>{simulationRunning ? "Stop Simulation" : "Start Simulation"}</button>
            </div>
            <DetectorHalo />
            <BeamLine />
            <ParticleMotionOverlay />
            <div className="absolute bottom-6 left-6 right-6 z-20 grid gap-3 md:grid-cols-3 xl:grid-cols-6">
              {eventSignatures.map((item, i) => (
                <button key={item} onClick={() => setSelectedEvent(item)} className={`border p-3 text-left backdrop-blur-xl transition ${selectedEvent === item ? "border-cyan-300/45 bg-cyan-300/[.12]" : "border-white/10 bg-black/45 hover:border-cyan-300/30"}`}>
                  <div className="text-[10px] font-black uppercase tracking-[.18em] text-slate-500">event {i + 1}</div>
                  <div className="mt-1 text-sm font-black text-cyan-100">{item}</div>
                </button>
              ))}
            </div>
          </div>
        </Panel>

        <div className="space-y-5">
          <Panel className="border-cyan-300/15 bg-[#050b16]/90 shadow-[0_24px_80px_rgba(0,0,0,.24)]">
            <Pill><Activity size={12}/> live telemetry</Pill>
            <div className="mt-3 text-xs leading-5 text-slate-400">Operational readout from the selected accelerator configuration.</div>
            <div className="mt-5 grid gap-3">
              {[ ["Beam Stability", beamStability, "%"], ["Collision Quality", collisionQuality, "%"], ["Velocity", (velocityFraction * 100).toFixed(2), "% c"], ["Speed", velocityMS.toLocaleString(), "m/s"], ["Acceleration", accelerationMS2.toExponential(2), "m/s²"], ["Magnetic Field", magneticTesla, "T"], ["RF Frequency", rfMHz, "MHz"], ["Beam Power", beamPowerMW, "MW"] ].map(([label, value, unit]) => (
                <div key={label} className="border border-white/10 bg-black/25 p-4 transition hover:border-cyan-300/25 hover:bg-cyan-300/[.035]">
                  <div className="flex justify-between gap-3 text-xs font-black uppercase tracking-[.18em] text-slate-500"><span>{label}</span><span className="text-cyan-100">{value} {unit}</span></div>
                  <div className="mt-2 h-2 overflow-hidden bg-slate-900"><div className="h-full bg-cyan-300 shadow-[0_0_18px_rgba(34,211,238,.65)]" style={{ width: `${Math.max(5, Math.min(99, typeof value === "number" ? value : collisionQuality))}%` }} /></div>
                </div>
              ))}
            </div>
          </Panel>
          <Panel className="border-amber-300/15 bg-[#0f0b05]/80 shadow-[0_24px_80px_rgba(0,0,0,.2)]">
            <Pill gold><ShieldCheck size={12}/> safety system</Pill>
            <div className="mt-4 space-y-2">{warnings.map((item) => <div key={item} className="border border-amber-200/[.12] bg-black/25 p-3 text-sm leading-5 text-amber-50">⚠ {item}</div>)}</div>
          </Panel>
        </div>
      </div>

      <Panel className="border-cyan-300/15 bg-[#050b16]/90 shadow-[0_32px_120px_rgba(0,0,0,.32)]">
        <div className="flex flex-wrap items-start justify-between gap-6 border-b border-cyan-300/10 pb-6">
          <div>
            <Pill><Radar size={12}/> collision command centre</Pill>
            <h2 className="mt-3 text-4xl font-black text-white">{collisionResult?.headline || "Collision event ready"}</h2>
            <p className="mt-2 max-w-4xl text-sm leading-6 text-slate-400">{collisionResult?.summary || "Start the accelerator to generate a full collision event. This command centre separates beam physics, target response, detector output and event reconstruction so the data is readable instead of cramped."}</p>
          </div>
          <div className="grid grid-cols-2 gap-3 text-right sm:grid-cols-4">
            <div className="border border-cyan-300/[.12] bg-black/25 p-3"><div className="text-2xl font-black text-cyan-100">{collisionQuality}%</div><div className="text-[10px] uppercase tracking-[.18em] text-slate-500">quality</div></div>
            <div className="border border-cyan-300/[.12] bg-black/25 p-3"><div className="text-2xl font-black text-cyan-100">{collisionEnergyGeV}</div><div className="text-[10px] uppercase tracking-[.18em] text-slate-500">GeV</div></div>
            <div className="border border-cyan-300/[.12] bg-black/25 p-3"><div className="text-2xl font-black text-cyan-100">{targetYield}%</div><div className="text-[10px] uppercase tracking-[.18em] text-slate-500">yield</div></div>
            <div className="border border-cyan-300/[.12] bg-black/25 p-3"><div className="text-2xl font-black text-cyan-100">{efficiency}%</div><div className="text-[10px] uppercase tracking-[.18em] text-slate-500">efficiency</div></div>
          </div>
        </div>

        <div className="mt-7 grid gap-4 md:grid-cols-5">
          {sequence.map(([label, value], i) => (
            <div key={label} className="border border-cyan-300/[.12] bg-black/[.24] p-5 shadow-[inset_0_1px_0_rgba(255,255,255,.04)]">
              <div className="text-xs font-black uppercase tracking-[.18em] text-slate-500">0{i + 1}</div>
              <div className="mt-2 text-xl font-black text-white">{label}</div>
              <div className="mt-3 h-2 bg-slate-900"><div className="h-full bg-cyan-300 shadow-[0_0_18px_rgba(34,211,238,.6)]" style={{ width: `${Math.max(4, Math.min(99, value))}%` }} /></div>
              <div className="mt-2 text-sm font-black text-cyan-100">{Math.max(4, Math.min(99, value))}%</div>
            </div>
          ))}
        </div>

        <div className="mt-7 grid gap-6 2xl:grid-cols-[1fr_1fr]">
          {[
            ["Beam Telemetry", beamTelemetryRows, "beam physics"],
            ["Target Response", targetResponseRows, `${targetElement.name} material response`],
            ["Detector Output", detectorOutputRows, `${selectedEvent} readout`],
            ["Collision Result", collisionResultRows, resultHeadline],
          ].map(([title, rows, subtitle]) => (
            <div key={title} className="border border-cyan-300/[.12] bg-black/[.24] p-6 shadow-[inset_0_1px_0_rgba(255,255,255,.04)]">
              <div className="flex items-center justify-between gap-3">
                <div>
                  <div className="text-xs font-black uppercase tracking-[.22em] text-cyan-200">{title}</div>
                  <div className="mt-1 text-xs leading-5 text-slate-500">{subtitle}</div>
                </div>
              </div>
              <div className="mt-5 grid gap-4 sm:grid-cols-2">
                {rows.map(([label, value, note, signal]) => (
                  <div key={`${title}-${label}`} className="border border-white/10 bg-slate-950/[.55] p-4 transition hover:border-cyan-300/20 hover:bg-slate-950/[.75]">
                    <div className="flex items-start justify-between gap-3">
                      <div className="text-[11px] font-black uppercase tracking-[.18em] text-slate-500">{label}</div>
                      <div className="text-right text-sm font-black text-cyan-100">{value}</div>
                    </div>
                    <div className="mt-2 text-xs leading-5 text-slate-400">{note}</div>
                    <div className="mt-3 h-1.5 bg-slate-900"><div className="h-full bg-cyan-300" style={{ width: `${Math.max(4, Math.min(99, Number(signal) || 35))}%` }} /></div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-7 grid gap-6 xl:grid-cols-[1.2fr_.8fr]">
          <div className="border border-cyan-300/[.12] bg-black/[.24] p-6">
            <div className="text-xs font-black uppercase tracking-[.22em] text-cyan-200">collision matrix</div>
            <div className="mt-2 text-xs leading-5 text-slate-500">Fast readout of energy transfer, material yield, target damage and detector confidence.</div>
            <div className="mt-4 space-y-4">
              {collisionMatrixRows.map(([label, value, note]) => (
                <div key={label} className="grid gap-3 md:grid-cols-[150px_1fr_80px] md:items-center">
                  <div className="text-sm font-black text-white">{label}</div>
                  <div className="h-4 border border-white/10 bg-slate-950">
                    <div className="h-full bg-gradient-to-r from-cyan-300/30 via-cyan-200 to-amber-200 shadow-[0_0_22px_rgba(34,211,238,.45)]" style={{ width: `${Math.max(4, Math.min(99, value))}%` }} />
                  </div>
                  <div className="text-right text-sm font-black text-cyan-100">{value}%</div>
                  <div className="md:col-start-2 md:col-span-2 text-xs leading-5 text-slate-500">{note}</div>
                </div>
              ))}
            </div>
          </div>

          <div className="border border-amber-300/[.12] bg-black/[.24] p-6">
            <div className="text-xs font-black uppercase tracking-[.22em] text-amber-200">live event feed</div>
            <div className="mt-2 text-xs leading-5 text-slate-500">Control-room sequence from injection through detector readout.</div>
            <div className="mt-4 max-h-[420px] space-y-3 overflow-auto pr-1">
              {eventLogRows.map(([time, title, body]) => (
                <div key={`${time}-${title}`} className="border border-white/10 bg-slate-950/[.55] p-3">
                  <div className="flex items-center justify-between gap-3"><span className="text-xs font-black text-cyan-100">{time}</span><span className="text-[10px] uppercase tracking-[.18em] text-slate-500">{simulationRunning ? "live" : "preview"}</span></div>
                  <div className="mt-1 text-sm font-black text-white">{title}</div>
                  <div className="mt-1 text-xs leading-5 text-slate-400">{body}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-7 grid gap-6 xl:grid-cols-[1fr_420px]">
          <div className="border border-cyan-300/[.12] bg-black/[.24] p-5">
            <div className="flex flex-wrap items-center justify-between gap-3"><div><div className="text-xs font-black uppercase tracking-[.22em] text-cyan-200">full collision dataset</div><div className="mt-2 text-xs leading-5 text-slate-500">Expanded export-ready telemetry for the current source, target and accelerator mode.</div></div><span className="border border-cyan-300/20 bg-cyan-300/8 px-3 py-1 text-[10px] font-black uppercase tracking-[.18em] text-cyan-100">report ready</span></div>
            <div className="mt-4 overflow-x-auto">
              <div className="min-w-[760px]">
                {collisionDataRows.map(([label, value, note]) => (
                  <div key={label} className="grid grid-cols-[190px_220px_1fr] gap-4 border-t border-white/8 py-3">
                    <div className="text-[11px] font-black uppercase tracking-[.18em] text-slate-500">{label}</div>
                    <div className="text-sm font-black text-white">{value}</div>
                    <div className="text-xs leading-5 text-slate-400">{note}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="border border-cyan-300/[.12] bg-black/[.24] p-5">
            <Pill><Target size={12}/> 118 element collision target</Pill>
            <div className="mt-4 flex items-end justify-between gap-3">
              <div><div className="text-5xl font-black text-white">{targetElement.symbol}</div><div className="text-lg font-black text-cyan-100">{targetElement.name}</div></div>
              <div className="text-right"><div className="text-3xl font-black text-amber-100">{beamElement.symbol}</div><div className="text-[10px] uppercase tracking-[.2em] text-slate-500">beam source</div></div>
            </div>
            <div className="mt-5 grid grid-cols-2 gap-2 text-center text-xs">
              <div className="border border-white/10 bg-black/25 p-3"><b className="text-cyan-100">{heatLoad}%</b><br/><span className="text-slate-500">Heat Load</span></div>
              <div className="border border-white/10 bg-black/25 p-3"><b className="text-cyan-100">{activationRisk}%</b><br/><span className="text-slate-500">Activation</span></div>
              <div className="border border-white/10 bg-black/25 p-3"><b className="text-cyan-100">{scatteringIndex}%</b><br/><span className="text-slate-500">Scattering</span></div>
              <div className="border border-white/10 bg-black/25 p-3"><b className="text-cyan-100">{targetYield}%</b><br/><span className="text-slate-500">Yield</span></div>
            </div>
            <div className="mt-5 grid gap-2">
              <button onClick={sendTargetToExplorer} className="border border-cyan-300/20 bg-black/30 px-4 py-3 text-sm font-black text-cyan-50 hover:bg-cyan-300/10">Open Target in Explorer</button>
              <button onClick={compareTargetMaterials} className="border border-cyan-300/20 bg-black/30 px-4 py-3 text-sm font-black text-cyan-50 hover:bg-cyan-300/10">Compare Beam + Target</button>
              <button onClick={forecastTarget} className="border border-cyan-300/20 bg-black/30 px-4 py-3 text-sm font-black text-cyan-50 hover:bg-cyan-300/10">Forecast Target Exposure</button>
              <button onClick={saveReport} className="border border-cyan-300/[.35] bg-cyan-300/[.12] px-4 py-3 text-sm font-black text-cyan-50 hover:bg-cyan-300/18">Export Accelerator Report</button>
            </div>
          </div>
        </div>
      </Panel>

      <Panel className="border-cyan-300/15 bg-[#050b16]/90 shadow-[0_24px_80px_rgba(0,0,0,.24)]">
        <div className="flex flex-wrap items-start justify-between gap-4"><div><Pill><Settings size={12}/> accelerator controls</Pill><p className="mt-3 text-xs leading-5 text-slate-400">Tune source, target, energy, RF, vacuum and detector controls. All current dropdowns and simulation logic are preserved.</p></div><div className="border border-cyan-300/15 bg-black/[.24] px-4 py-3 text-right"><div className="text-xs uppercase tracking-[.18em] text-slate-500">simulation</div><div className="text-sm font-black text-cyan-100">{simulationRunning ? "Running" : "Ready"}</div></div></div>
        <div className="mt-5 grid gap-4 md:grid-cols-2 xl:grid-cols-4">
          <label><span className="text-xs font-black uppercase tracking-[.2em] text-slate-500">Particle type</span><select value={particle} onChange={(e) => setParticle(e.target.value)} className="mt-2 w-full border border-cyan-300/15 bg-slate-950 p-3 text-sm outline-none">{particles.map((item) => <option key={item}>{item}</option>)}</select></label>
          <label><span className="text-xs font-black uppercase tracking-[.2em] text-slate-500">Beam element source</span><select value={beamSymbol} onChange={(e) => setBeamSymbol(e.target.value)} className="mt-2 w-full border border-cyan-300/15 bg-slate-950 p-3 text-sm outline-none">{elements.map((item) => <option key={item.symbol} value={item.symbol}>{item.atomicNumber}. {item.name} ({item.symbol})</option>)}</select></label>
          <label><span className="text-xs font-black uppercase tracking-[.2em] text-slate-500">Collision target element</span><select value={targetSymbol} onChange={(e) => setTargetSymbol(e.target.value)} className="mt-2 w-full border border-cyan-300/15 bg-slate-950 p-3 text-sm outline-none">{elements.map((item) => <option key={item.symbol} value={item.symbol}>{item.atomicNumber}. {item.name} ({item.symbol})</option>)}</select></label>
          {[ ["Beam energy", beamEnergy, setBeamEnergy], ["Magnetic field", magneticField, setMagneticField], ["RF frequency", rfFrequency, setRfFrequency], ["Vacuum quality", vacuum, setVacuum], ["Detector sensitivity", detectorSensitivity, setDetectorSensitivity], ["Collimation", collimation, setCollimation], ["Beam current", beamCurrent, setBeamCurrent], ["Pulse rate", pulseRate, setPulseRate] ].map(([label, value, setter]) => (
            <label key={label} className="block">
              <div className="flex justify-between text-xs font-black uppercase tracking-[.18em] text-slate-500"><span>{label}</span><span className="text-cyan-100">{value}%</span></div>
              <input type="range" min="10" max="100" value={value} onChange={(e) => setter(Number(e.target.value))} className="mt-3 w-full accent-cyan-300" />
            </label>
          ))}
        </div>
      </Panel>
    </div>
  );
}



function LabMetricCard({ label, value, note, accent = "cyan" }) {
  const accentClass = accent === "amber" ? "text-amber-100 border-amber-300/18 bg-amber-300/[.045]" : accent === "rose" ? "text-rose-100 border-rose-300/18 bg-rose-300/[.045]" : accent === "emerald" ? "text-emerald-100 border-emerald-300/18 bg-emerald-300/[.045]" : "text-cyan-100 border-cyan-300/18 bg-cyan-300/[.045]";
  return (
    <div className={`border p-4 ${accentClass}`}>
      <div className="text-[10px] font-black uppercase tracking-[.22em] text-slate-500">{label}</div>
      <div className="mt-2 text-3xl font-black text-white">{value}</div>
      <div className="mt-2 text-xs leading-5 text-slate-400">{note}</div>
    </div>
  );
}

function LabSignalBar({ label, value, note }) {
  return (
    <div className="border border-white/10 bg-black/25 p-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <div className="text-sm font-black text-white">{label}</div>
          {note && <div className="mt-1 text-xs text-slate-500">{note}</div>}
        </div>
        <div className="text-lg font-black text-cyan-100">{value}%</div>
      </div>
      <div className="mt-3 h-2 bg-slate-950">
        <div className="h-full bg-cyan-300" style={{ width: `${Math.max(3, Math.min(100, value))}%` }} />
      </div>
    </div>
  );
}

function labElementOptions() {
  return elements.map((e) => <option key={e.symbol} value={e.symbol}>{e.atomicNumber}. {e.name} ({e.symbol})</option>);
}


function AdvancedLabDataTile({ label, value, unit = "", note = "", tone = "cyan" }) {
  const toneClass = tone === "amber" ? "border-amber-300/20 bg-amber-300/[.055] text-amber-100" : tone === "rose" ? "border-rose-300/20 bg-rose-300/[.055] text-rose-100" : tone === "emerald" ? "border-emerald-300/20 bg-emerald-300/[.055] text-emerald-100" : "border-cyan-300/20 bg-cyan-300/[.055] text-cyan-100";
  return (
    <div className={`border p-4 ${toneClass}`}>
      <div className="text-[10px] font-black uppercase tracking-[.22em] text-slate-500">{label}</div>
      <div className="mt-2 flex items-end gap-1"><span className="text-3xl font-black text-white">{value}</span>{unit && <span className="pb-1 text-xs font-black uppercase tracking-[.16em] text-slate-400">{unit}</span>}</div>
      {note && <div className="mt-2 text-xs leading-5 text-slate-400">{note}</div>}
    </div>
  );
}

function AdvancedLabDataStrip({ label, value, note, tone = "cyan" }) {
  const color = tone === "amber" ? "bg-amber-300" : tone === "rose" ? "bg-rose-300" : tone === "emerald" ? "bg-emerald-300" : "bg-cyan-300";
  const pct = Math.max(2, Math.min(100, Math.round(Number(value) || 0)));
  return (
    <div className="border border-white/10 bg-black/25 p-4">
      <div className="flex items-start justify-between gap-4"><div><div className="text-sm font-black text-white">{label}</div>{note && <div className="mt-1 text-xs leading-5 text-slate-500">{note}</div>}</div><div className="text-lg font-black text-cyan-100">{pct}%</div></div>
      <div className="mt-3 h-2 bg-slate-950"><div className={`h-full ${color}`} style={{ width: `${pct}%` }} /></div>
    </div>
  );
}

function AdvancedLabSection({ eyebrow, title, children, action }) {
  return (
    <Panel className="relative overflow-hidden border-cyan-300/20 bg-[#030914]/95 shadow-[0_0_54px_rgba(34,211,238,.055)]">
      <div className="pointer-events-none absolute inset-0 opacity-40" style={{ backgroundImage: "linear-gradient(rgba(34,211,238,.055) 1px, transparent 1px), linear-gradient(90deg, rgba(34,211,238,.045) 1px, transparent 1px)", backgroundSize: "42px 42px" }} />
      <div className="relative z-10 flex flex-wrap items-start justify-between gap-4">
        <div><div className="text-xs font-black uppercase tracking-[.24em] text-cyan-200">{eyebrow}</div><h2 className="mt-2 text-3xl font-black text-white">{title}</h2></div>
        {action}
      </div>
      <div className="relative z-10 mt-5">{children}</div>
    </Panel>
  );
}

